$ErrorActionPreference="Stop";$Modules=@("frontend","backend");$Root=Get-Location;foreach($Mod in $Modules){if(Test-Path $Mod){Write-Host "Checking $Mod" -ForegroundColor Green;Set-Location (Join-Path $Root $Mod);npm audit fix; $raw=npm outdated --json 2>$null;if($raw -and $raw -ne "{}"){$out=$raw|ConvertFrom-Json;$pkgs=$out|Get-Member -MemberType NoteProperty|Select-Object -ExpandProperty Name;$safe=@();$maj=@();foreach($p in $pkgs){$d=$out.$p;if($d.current -and $d.latest -and ($d.current -ne $d.latest)){$c=$d.current.Split('.')[0];$l=$d.latest.Split('.')[0];if($c -eq $l){$safe+=$p}else{$maj+=[PSCustomObject]@{Pkg=$p;Cur=$d.current;Lat=$d.latest}}}};if($safe.Count -gt 0){Write-Host "Updating Safe..." -ForegroundColor Cyan;npm update};if($maj.Count -gt 0){Write-Host "MAJOR updates found:" -ForegroundColor Yellow;$maj|Format-Table|Out-String|Write-Host;$ans=Read-Host "Apply Major? (y/n)";if($ans -eq 'y'){npx npm-check-updates -u;npm install}}};npm dedupe;Set-Location $Root}};Write-Host "DONE" -ForegroundColor Greenolving